5412	\begin{lemma}[Pushforward of quasi-coherent modules is quasi-coherent (Stacks 01XJ)]
5413	  \label{lem:pushforward_isQuasicoherent}
5414	  \lean{AlgebraicGeometry.Scheme.Modules.pushforward_isQuasicoherent}
5415	  \leanok
5416	  \textit{Source: Stacks~\href{https://stacks.math.columbia.edu/tag/01XJ}{01XJ}
5417	  (preservation of quasi-coherence under pushforward).}
5418	  Let \(f : X \to Y\) be a quasi-compact, quasi-separated morphism of
5419	  schemes, and let \(\mathcal{F}\) be a quasi-coherent
5420	  \(\mathcal{O}_X\)-module. Then \(f_* \mathcal{F}\) is a quasi-coherent
5421	  \(\mathcal{O}_Y\)-module. Mathlib \texttt{b80f227} ships no
5422	  \texttt{IsQuasicoherent.pushforward} instance at the
5423	  \texttt{Scheme.Modules} layer.
5424	\end{lemma}
5425	\begin{proof}
5426	  \leanok
5427	  \uses{lem:pushforward_section_localization, lem:fromTildeGamma_pullback_fromSpec_converse}
5428	  Quasi-coherence is local on $Y$, so it suffices to produce a presentation
5429	  of the slice of $f_* \mathcal{F}$ over each affine open $U \subseteq Y$.
5430	  By \Cref{lem:pushforward_section_localization} all basic-open section
5431	  restrictions of $f_* \mathcal{F}$ at $U$ are localizations, so by
5432	  \Cref{lem:fromTildeGamma_pullback_fromSpec_converse} the pullback of
5433	  $f_* \mathcal{F}$ along $\operatorname{Spec} \Gamma(Y, U) \to Y$ is
5434	  isomorphic to the tilde of its global sections. A tilde admits a global
5435	  presentation; transporting it along
5436	  $U \hookrightarrow Y = (\operatorname{Spec}\Gamma(Y,U) \cong U)
5437	  \hookrightarrow Y$ yields a presentation of the geometric restriction of
5438	  $f_* \mathcal{F}$ to $U$, hence of the slice. (The previously sketched
5439	  ``right adjoints preserve quasi-coherence'' argument is not a proof:
5440	  adjointness yields colimit preservation only.)
5441	\end{proof}
